import { getCandidates } from '@/lib/actions';
import { StatusBadge } from '@/components/StatusBadge';
import { PrintButton } from '@/components/PrintButton';

export const dynamic = 'force-dynamic';

export default async function ScoreboardPage() {
    const candidates = await getCandidates();

    // Sort by average score descending
    const sortedCandidates = [...candidates].sort((a, b) => b.averageScore - a.averageScore);

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h1 className="text-2xl font-bold text-slate-900">Scoreboard</h1>
                <PrintButton />
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <table className="w-full text-left">
                    <thead className="bg-slate-50 border-b border-slate-200">
                        <tr>
                            <th className="px-6 py-4 font-bold text-slate-700 w-16">Rank</th>
                            <th className="px-6 py-4 font-bold text-slate-700">Candidate</th>
                            <th className="px-6 py-4 font-bold text-slate-700">Track</th>
                            <th className="px-6 py-4 font-bold text-slate-700 text-center">Score</th>
                            <th className="px-6 py-4 font-bold text-slate-700">Status</th>
                            <th className="px-6 py-4 font-bold text-slate-700">Tags</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                        {sortedCandidates.map((c, index) => (
                            <tr key={c.id} className="hover:bg-slate-50/50">
                                <td className="px-6 py-4 bg-slate-50/30 font-mono text-slate-400 font-semibold">{index + 1}</td>
                                <td className="px-6 py-4 font-medium text-slate-900">{c.name}</td>
                                <td className="px-6 py-4 text-slate-600">{c.track}</td>
                                <td className="px-6 py-4 text-center">
                                    {c.averageScore > 0 ? (
                                        <span className={`inline-block px-3 py-1 rounded font-bold ${c.averageScore >= 60 ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-700'}`}>
                                            {c.averageScore}
                                        </span>
                                    ) : (
                                        <span className="text-slate-300">-</span>
                                    )}
                                </td>
                                <td className="px-6 py-4"><StatusBadge status={c.status} /></td>
                                <td className="px-6 py-4">
                                    <div className="flex flex-wrap gap-1">
                                        {c.tags?.slice(0, 3).map(t => (
                                            <span key={t} className="text-[10px] uppercase px-1.5 py-0.5 bg-slate-100 text-slate-500 rounded border border-slate-200">{t}</span>
                                        ))}
                                        {c.tags?.length > 3 && <span className="text-[10px] text-slate-400">+{c.tags.length - 3}</span>}
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
}
